        const throughObj = {
            sink: function(read) {
                sinkCalled = true;
                this.read = read;
            },
            source: function(end, cb) {
                this.read(end, function(end, data) {
                    if (end) return cb(end);
                    cb(null, data * 3);
                });
            }
        };

        const source = createSource([1, 2]);
        const sink = createSink((err, results) => {
            assert.strictEqual(err, null);
            assert.deepStrictEqual(results, [3, 6]);
            assert.strictEqual(sinkCalled, true);
            done();
        });

        pull_stream(source, throughObj, sink);
    });

    it('should handle different argument lengths in partial application', function(done) {
        // Test case 2 (length = 2)
